function escapeRegex(s) {
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function parseArg(name) {
  const key = String(name).replace(/^--/, '');
  const idx = process.argv.findIndex((a) => a === `--${key}`);
  if (idx >= 0 && process.argv[idx + 1] != null) return process.argv[idx + 1];
  return undefined;
}

function parseBool(v, defaultValue = false) {
  if (v == null) return defaultValue;
  const s = String(v).trim().toLowerCase();
  if (['1', 'true', 'yes', 'y', 'on'].includes(s)) return true;
  if (['0', 'false', 'no', 'n', 'off'].includes(s)) return false;
  return defaultValue;
}

function sumTransferTxDays(txs, dir, leaveType) {
  const wantLt = String(leaveType || '').toUpperCase();
  const prefix = dir === 'IN' ? 'MONTHLY_POOL_TRANSFER_IN_' : 'MONTHLY_POOL_TRANSFER_OUT_';
  if (!Array.isArray(txs)) return 0;
  let sum = 0;
  for (const t of txs) {
    const ag = String(t?.autoGeneratedType || '');
    if (!ag.startsWith(prefix)) continue;
    if (String(t?.leaveType || '').toUpperCase() !== wantLt) continue;
    sum += Number(t.days) || 0;
  }
  return Math.round(sum * 100) / 100;
}

/** Count rows about to be stripped (all FY docs for employee). */
async function countMonthlyPoolTransferArtifacts(employeeId) {
  const docs = await LeaveRegisterYear.find({ employeeId }).select('financialYear months').lean();
  let transferTxRows = 0;
  let slotsWithCarryMeta = 0;
  for (const d of docs) {
    for (const s of d.months || []) {
      if (s.poolCarryForwardIn || s.poolCarryForwardOut != null || s.poolCarryForwardOutAt) {
        slotsWithCarryMeta += 1;
      }
      for (const t of s.transactions || []) {
        if (leaveRegisterYearService.isMonthlyPoolCarrySlotTransaction(t)) {
          transferTxRows += 1;
        }
      }
    }
  }
  return { transferTxRows, slotsWithCarryMeta, fyDocCount: docs.length };
}

function numOrDash(v) {
  if (v === null || v === undefined || v === '—') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

/**
 * UI grid: Balance = Credits + Carried in − Used − Transfer out, Used = debits + lock.
 * Confirms API `poolBalance` matches that identity when present.
 */
function poolBalanceGridAuditIssues(rm) {
  const triples = [
    ['CL', rm.policyScheduledCl, rm.cl],
    ['CCL', rm.policyScheduledCco, rm.ccl],
    ['EL', rm.policyScheduledEl, rm.el],
  ];
  const bad = [];
  for (const [lt, pol, b] of triples) {
    if (!b || b.poolBalance == null || !Number.isFinite(Number(b.poolBalance))) continue;
    const cr = numOrDash(pol);
    const tin = numOrDash(b.transferIn);
    if (cr == null && tin == null) continue;
    const tout = Number(b.transferOut) || 0;
    const ul = (Number(b.used) || 0) + (Number(b.locked) || 0);
    const expected = (cr ?? 0) + (tin ?? 0) - ul - tout;
    const actual = Number(b.poolBalance);
    if (Math.abs(expected - actual) > 0.02) bad.push(lt);
  }
  return bad;
}

/** Per month: OK if register transfer columns match summed FY-slot txs for CL/CCL/EL. */
function poolTransferAuditStatus(rm, txs) {
  const checks = [
    ['CL', rm.cl?.transferIn, rm.cl?.transferOut, 'CL'],
    ['CCL', rm.ccl?.transferIn, rm.ccl?.transferOut, 'CCL'],
    ['EL', rm.el?.transferIn, rm.el?.transferOut, 'EL'],
  ];
  const bad = [];
  for (const [, vin, vout, lt] of checks) {
    const a = numOrDash(vin);
    const b = numOrDash(vout);
    const tin = sumTransferTxDays(txs, 'IN', lt);
    const tout = sumTransferTxDays(txs, 'OUT', lt);
    if (a !== tin || b !== tout) bad.push(lt);
  }
  return bad.length === 0 ? 'OK' : `MISMATCH:${bad.join(',')}`;
}

/** Closed payroll slots strictly before open cycle start, optionally capped by payroll month/year. */
async function countPlannedCarryEdges(employeeId, asOf, throughPayrollMonth, throughPayrollYear) {
  const periodInfo = await dateCycleService.getPeriodInfo(asOf);
  const currentCycleStart = periodInfo?.payrollCycle?.startDate;
  const carryCutoff =
    currentCycleStart != null ? new Date(currentCycleStart) : createISTDate(getTodayISTDateString());

  const closings = [];
  const refreshed = await LeaveRegisterYear.find({ employeeId }).sort({ financialYearStart: 1 }).lean();
  for (const d of refreshed) {
    for (const slot of d.months || []) {
      if (!slot.payPeriodEnd) continue;
      if (!leaveRegisterYearService.isPayrollPeriodClosedBeforeAsOf(slot.payPeriodEnd, carryCutoff)) continue;
      closings.push({
        pm: Number(slot.payrollCycleMonth),
        py: Number(slot.payrollCycleYear),
        t: new Date(slot.payPeriodEnd).getTime(),
      });
    }
  }
  const seen = new Set();
  let ordered = closings
    .filter((c) => {
      if (!Number.isFinite(c.pm) || !Number.isFinite(c.py)) return false;
      const k = `${c.py}-${c.pm}`;
      if (seen.has(k)) return false;
      seen.add(k);
      return true;
    })
    .sort((a, b) => a.t - b.t);

  if (throughPayrollMonth != null && Number.isFinite(Number(throughPayrollMonth))) {
    const capM = Number(throughPayrollMonth);
    const capY = throughPayrollYear;
    ordered = ordered.filter((c) => {
      if (Number(c.pm) > capM) return false;
      if (capY != null && Number.isFinite(Number(capY)) && Number(c.py) !== Number(capY)) return false;
      return true;
    });
  }

  return {
    edges: ordered.length,
    carryCutoffIso: carryCutoff?.toISOString?.() || String(carryCutoff),
    currentPayrollCycle: periodInfo?.payrollCycle
      ? { month: periodInfo.payrollCycle.month, year: periodInfo.payrollCycle.year }
      : null,
  };
}

async function recalcOne(employeeId) {
  await leaveRegisterYearLedgerService.recalculateRegisterBalances(employeeId, 'CL', null);
  await leaveRegisterYearLedgerService.recalculateRegisterBalances(employeeId, 'CCL', null);
  await leaveRegisterYearLedgerService.recalculateRegisterBalances(employeeId, 'EL', null);
}

